// ============================================================
// NODE: Re-validate and Attempt Re-insert
// PURPOSE: For each failure row, attempt to re-insert into
//          supplier_invoices. Parse raw_payload back to fields.
// ============================================================

const items = $input.all();
const results = [];

for (const inputItem of items) {
  const failure = inputItem.json;

  // Parse raw_payload if it's a string
  let payload = failure.raw_payload;
  if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); } catch(e) { payload = {}; }
  }

  // Merge failure record with parsed payload
  const record = {
    id:              failure.id,
    invoice_number:  failure.invoice_number  || payload.invoice_number  || null,
    supplier_number: failure.supplier_number || payload.supplier_number || null,
    supplier_name:   failure.supplier_name   || payload.supplier_name   || null,
    department:      payload.department      || null,
    amount_excl_vat: payload.amount_excl_vat || null,
    vat:             payload.vat             || null,
    amount_incl_vat: payload.amount_incl_vat || null,
    invoice_date:    payload.invoice_date    || null,
    source_file_name: failure.source_file_name || payload.sourceFileName || null,
    source_hash:     failure.source_hash     || payload.sourceHash      || null,
    validation_notes: failure.validation_notes || null,
    retry_count:     (failure.retry_count || 0) + 1
  };

  // Check if all required fields are present for re-insert
const MAX_RETRIES = 3;
const canRetry = !!(record.invoice_number && record.supplier_number &&
                 record.supplier_name && record.department &&
                 record.amount_excl_vat && record.invoice_date) &&
                 record.retry_count <= MAX_RETRIES;

  console.log(`[Retry] ${record.invoice_number} / ${record.supplier_number} — retry #${record.retry_count} — canRetry: ${canRetry}`);

  results.push({
    json: {
      ...record,
      can_retry: canRetry
    }
  });
}

return results;

let reinsertedCount = 0;
let updatedCount = 0;
let exhaustedCount = 0;
const exhaustedRows = [];

try {
 const reinserted = $('🗑️ Delete — Remove from Failures').all();
reinsertedCount = reinserted ? reinserted.length : 0;


} catch(e) { reinsertedCount = 0; }

try {
  const retryFailed = $('📝 Update — Retry Failed, Increment Count').all();
  updatedCount = retryFailed ? retryFailed.length : 0;
} catch(e) { updatedCount = 0; }

try {
  const exhausted = $('📝 Update — Mark Exhausted').all();
  if (exhausted && exhausted.length > 0) {
    exhaustedCount = exhausted.length;
    for (const e of exhausted) {
      exhaustedRows.push({
        invoice_number: e.json.invoice_number || 'N/A',
        retry_count: e.json.retry_count || 3
      });
    }
  }
} catch(e) { exhaustedCount = 0; }

const ingestTime = new Date(new Date().getTime() + 2 * 60 * 60 * 1000)
  .toISOString().replace('T', ' ').substring(0, 19) + ' SAST';

console.log(`[Retry Metrics] Re-inserted: ${reinsertedCount} | Updated: ${updatedCount} | Exhausted: ${exhaustedCount}`);

return [{
  json: {
    reinsertedCount,
    updatedCount,
    exhaustedCount,
    exhaustedRows,
    ingestTime,
    hasExhausted: exhaustedCount > 0
  }
}];

